const int N=3e5 +5;

int E[N], W[N];

char a[N];



int main(){



    scanf("%d", &n);

    scanf(" %s", a);



    for(int i=1; i<=n; ++i){

        E[i]=E[i-1]+(a[i-1]=='E');

        W[i]=W[i-1]+(a[i-1]=='W');

    }



    int mn=n;

    for(int i=0; i<n; ++i){

        int num=W[i]+(E[n]-E[i+1]);

        mn=min(mn, num);

    }



    printf("%d\n", mn);



    return 0;

}

